module temperature_sensor (  
    input wire clk,  
    input wire [3:0] temperature,  
    output reg alarm  
);  
    parameter THRESHOLD = 4'd8;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (temperature > THRESHOLD)  
            alarm <= 1'b1;  
        else  
            alarm <= 1'b0;  
    end  
endmodule
